<template>
  <div class="spacer">
    <div class="box container has-background-white">

      <div class="columns">
        <div class="column">
          <b-field label="Type of property">
            <b-input v-model="propertiesPage.propertyType"></b-input>
          </b-field>
        </div>
        <div class="column">
          <b-field label="Value of the property">
            <b-input v-model="propertiesPage.value"></b-input>
          </b-field>
        </div>
        <div class="column">
          <b-field label="Property taxes">
            <b-input v-model="propertiesPage.taxes"></b-input>
          </b-field>
        </div>
      </div>

      <div class="columns">
        <div class="column is-two-thirds">
          <b-field grouped>
            <b-field label="Unit">
              <b-input placeholder="optional" type="number" v-model="propertiesPage.propertyAddress.unit">
              </b-input>
            </b-field>
            <b-field label="Street" expanded>
              <b-input icon="home" type="text" v-model="propertiesPage.propertyAddress.street">
              </b-input>
            </b-field>
          </b-field>
          <div class="columns">
            <div class="column">
              <b-field label="City" expanded>
                <b-input type="text" v-model="propertiesPage.propertyAddress.city"></b-input>
              </b-field>
            </div>
            <div class="column">
              <b-field label="Province" expanded>
                <b-input type="text" v-model="propertiesPage.propertyAddress.province"></b-input>
              </b-field>
            </div>
          </div>
        </div>
        <div class="column">
          <div class="columns">
            <div class="column">
              <b-field label="Your rental income">
                <b-input v-model="propertiesPage.rentalIncome"></b-input>
              </b-field>
            </div>
          </div>
          <div class="columns">
            <div class="column">
              <b-field label="Your rental agreement">
                <b-select placeholder="Pick one" v-model="propertiesPage.rentalAgreement" required expanded>
                  <option value="Available">Available</option>
                  <option value="Month-to-month">Month-to-month</option>
                </b-select>
              </b-field>
            </div>
          </div>
        </div>
      </div>

      <div class="columns">
        <div class="column">
          <b-field label="Do you mortgage your property?">
            <div class="input is-blank">
              <b-radio id="Yes" native-value="Yes" v-model="propertiesPage.mortgage">
                Yes
              </b-radio>
              <b-radio id="No" native-value="No" v-model="propertiesPage.mortgage">
                No
              </b-radio>
            </div>
          </b-field>
        </div>
        <div class="column">
          <transition name="fadeUp" mode="out-in">
            <b-field label="Mortgage amount" v-if="propertiesPage.mortgage === 'Yes'">
              <b-input v-model="propertiesPage.mortgageAmount" placeholder="Total mortgage amount" type="number"></b-input>
            </b-field>
          </transition>
        </div>
        <div class="column">
          <transition name="fadeUp" mode="out-in">
            <b-field label="Your interest rate" v-if="propertiesPage.mortgage === 'Yes'">
              <b-input v-model="propertiesPage.mortgageRate" placeholder="The percent value" type="number"></b-input>
            </b-field>
          </transition>
        </div>
      </div>
      <hr>
      <back-next back="/employment" next="/signatures"></back-next>
    </div>
  </div>
</template>

<script>
export default {
  created() {
    this.emit("deets", [this.page, this.heading]);
  },
  data() {
    return {
      page: "Page 4",
      haeding: "Your Properties",
      propertiesPage: {
        propertyAddress: {
          unit: null,
          street: null,
          city: null,
          province: null,
          postal: null
        }
      }
    };
  }
};
</script>
