<template>
  <section>
    <div class="columns">
      <div class="column">
        <b-field label="Your Full Name">
          <b-input v-model="additionalPersonalPage.fullName"></b-input>
        </b-field>
      </div>
      <div class="column">
        <b-field label="Your date of birth">
          <b-datepicker placeholder="Click to select" icon="calendar" v-model="additionalPersonalPage.dateOfBirth"></b-datepicker>
        </b-field>
      </div>
    </div>

    <div class="columns">
      <div class="column">
        <b-field label="Marital status">
          <b-select expanded required v-model="additionalPersonalPage.maritalStatus">
            <option value="Single">Single</option>
            <option value="Married">Married</option>
            <option value="Divorced">Divorced</option>
            <option value="Common Law">Common Law</option>
          </b-select>
        </b-field>
      </div>
      <div class="column">
        <b-field label="Citizen status">
          <b-select expanded required v-model="additionalPersonalPage.citizenship">
            <option value="Canadian citizen">Canadian citizen</option>
            <option value="Landed Immigrant">Landed Immigrant</option>
            <option value="Permanent Resident">Permanent Resident</option>
          </b-select>
        </b-field>
      </div>
      <div class="column">
        <b-field label="Dependents">
          <div class="input is-blank">
            <b-radio id="0" native-value="0" v-model="additionalPersonalPage.dependents">
              0
            </b-radio>
            <b-radio id="1" native-value="1" v-model="additionalPersonalPage.dependents">
              1
            </b-radio>
            <b-radio id="2" native-value="2" v-model="additionalPersonalPage.dependents">
              2
            </b-radio>
            <b-radio id="3" native-value="3" v-model="additionalPersonalPage.dependents">
              3
            </b-radio>
            <b-radio id="4+" native-value="4+" v-model="additionalPersonalPage.dependents">
              4+
            </b-radio>
          </div>
        </b-field>
      </div>
    </div>

    <div class="columns">
      <div class="column is-two-thirds">
        <b-field grouped>
          <b-field label="Unit">
            <b-input placeholder="optional" type="number" v-model="additionalPersonalPage.address.unit">
            </b-input>
          </b-field>
          <b-field label="Street" expanded>
            <b-input icon="home" type="text" v-model="additionalPersonalPage.address.street">
            </b-input>
          </b-field>
        </b-field>
        <div class="columns">
          <div class="column">
            <b-field label="City" expanded>
              <b-input type="text" v-model="additionalPersonalPage.address.city"></b-input>
            </b-field>
          </div>
          <div class="column">
            <b-field label="Province" expanded>
              <b-input type="text" v-model="additionalPersonalPage.address.province"></b-input>
            </b-field>
          </div>
          <div class="column">
            <b-field label="Postal code" expanded>
              <b-input type="text" v-model="additionalPersonalPage.address.postal"></b-input>
            </b-field>
          </div>
        </div>
      </div>
      <div class="column">
        <div class="columns">
          <div class="column">
            <b-field label="Your phone number">
              <b-input icon="phone" type="phone" placeholder="(###)###-####"></b-input>
            </b-field>
          </div>
        </div>
        <div class="columns">
          <div class="column">
            <b-field label="Your email">
              <b-input v-model="additionalPersonalPage.email" icon="envelope" type="email"></b-input>
            </b-field>
          </div>
        </div>
      </div>
    </div>

    <div class="columns">
      <div class="column is-one-third">
        <b-field label="How long have you lived here?">
          <b-input v-model="additionalPersonalPage.address.timeResided" type="text"></b-input>
        </b-field>
      </div>
      <div class="column is-one-third">
        <b-field label="Status of your residence?">
          <b-select expanded required v-model="additionalPersonalPage.address.residenceStatus">
            <option value="Own">I own my residence</option>
            <option value="Rent">I rent</option>
            <option value="Parents">I live with my parents</option>
          </b-select>
        </b-field>
      </div>
    </div>
    <hr>
  </section>
</template>

<script>
export default {
  // created() {
  //   this.$emit("deets", [this.page, this.heading]);
  // },
  data() {
    return {
      // page: "Page 2.1",
      // heading: "Additional Personal Forms",
      additionalPersonalPage: {
        dateOfBirth: null,
        maritalStatus: "",
        citizenship: "",
        dependents: "",
        fullName: "",
        address: {
          unit: "",
          street: "",
          city: "",
          province: "",
          postal: "",
          residenceStatus: "",
          timeResided: ""
        }
      }
    };
  }
};
</script>
