<template>
  <div class="spacer">
    <transition name="fadeUp" mode="out-in">
      <div class="box container has-background-white" v-if="noOtherForms">

        <div class="columns">
          <div class="column">
            <b-field label="Are you the sole applicant?">
              <b-select placeholder="Select an amount" expanded required @input="formAmount">
                <option v-for="amount in applicants" :value="amount" :key="amount">
                  {{ amount }}
                </option>
              </b-select>
            </b-field>
          </div>
          <div class="column">
            <b-field label="Your Full Name">
              <b-input v-model="personalPage.fullName"></b-input>
            </b-field>
          </div>
          <div class="column">
            <b-field label="Your date of birth">
              <b-datepicker placeholder="Click to select" icon="calendar" v-model="personalPage.dateOfBirth"></b-datepicker>
            </b-field>
          </div>
        </div>

        <div class="columns">
          <div class="column">
            <b-field label="Marital status">
              <b-select expanded required v-model="personalPage.maritalStatus">
                <option value="Single">Single</option>
                <option value="Married">Married</option>
                <option value="Divorced">Divorced</option>
                <option value="Common Law">Common Law</option>
              </b-select>
            </b-field>
          </div>
          <div class="column">
            <b-field label="Citizen status">
              <b-select expanded required v-model="personalPage.citizenship">
                <option value="Canadian citizen">Canadian citizen</option>
                <option value="Landed Immigrant">Landed Immigrant</option>
                <option value="Permanent Resident">Permanent Resident</option>
              </b-select>
            </b-field>
          </div>
          <div class="column">
            <b-field label="Dependents">
              <div class="input is-blank">
                <b-radio id="0" native-value="0" v-model="personalPage.dependents">
                  0
                </b-radio>
                <b-radio id="1" native-value="1" v-model="personalPage.dependents">
                  1
                </b-radio>
                <b-radio id="2" native-value="2" v-model="personalPage.dependents">
                  2
                </b-radio>
                <b-radio id="3" native-value="3" v-model="personalPage.dependents">
                  3
                </b-radio>
                <b-radio id="4+" native-value="4+" v-model="personalPage.dependents">
                  4+
                </b-radio>
              </div>
            </b-field>
          </div>
        </div>

        <div class="columns">
          <div class="column is-two-thirds">
            <b-field grouped>
              <b-field label="Unit">
                <b-input placeholder="optional" type="number" v-model="personalPage.personalAddress.unit">
                </b-input>
              </b-field>
              <b-field label="Street" expanded>
                <b-input icon="home" type="text" v-model="personalPage.personalAddress.street">
                </b-input>
              </b-field>
            </b-field>
            <div class="columns">
              <div class="column">
                <b-field label="City" expanded>
                  <b-input type="text" v-model="personalPage.personalAddress.city"></b-input>
                </b-field>
              </div>
              <div class="column">
                <b-field label="Province" expanded>
                  <b-input type="text" v-model="personalPage.personalAddress.province"></b-input>
                </b-field>
              </div>
              <div class="column">
                <b-field label="Postal code" expanded>
                  <b-input type="text" v-model="personalPage.personalAddress.postal"></b-input>
                </b-field>
              </div>
            </div>
          </div>
          <div class="column">
            <div class="columns">
              <div class="column">
                <b-field label="Your phone number">
                  <b-input icon="phone" type="phone" placeholder="(###)###-####"></b-input>
                </b-field>
              </div>
            </div>
            <div class="columns">
              <div class="column">
                <b-field label="Your email">
                  <b-input v-model="personalPage.email" icon="envelope" type="email"></b-input>
                </b-field>
              </div>
            </div>
          </div>
        </div>

        <div class="columns">
          <div class="column is-one-third">
            <b-field label="How long have you lived here?">
              <b-input v-model="personalPage.personalAddress.timeResided" type="text"></b-input>
            </b-field>
          </div>
          <div class="column is-one-third">
            <b-field label="Status of your residence?">
              <b-select expanded required v-model="personalPage.personalAddress.residenceStatus">
                <option value="Own">I own my residence</option>
                <option value="Rent">I rent</option>
                <option value="Parents">I live with my parents</option>
              </b-select>
            </b-field>
          </div>
        </div>
        <hr>
        <back-next back="/start" :next="getForms"></back-next>
      </div>
      <router-view :forms="additionalForms" @deets="reEmit"></router-view>
    </transition>
  </div>
</template>

<script>
import Router from "../router";
export default {
  created() {
    this.$emit("deets", [this.page, this.heading]);
  },
  data() {
    return {
      page: "Page 2",
      heading: "Personal Information",
      applicants: [
        "Yes",
        "I will need one more form",
        "I will need two more forms",
        "I will need three more forms"
      ],
      additionalForms: 0,
      personalPage: {
        dateOfBirth: null,
        maritalStatus: "",
        citizenship: "",
        dependents: "",
        fullName: "",
        personalAddress: {
          unit: "",
          street: "",
          city: "",
          province: "",
          postal: "",
          residenceStatus: "",
          timeResided: ""
        }
      }
    };
  },
  methods: {
    formAmount(amount) {
      this.additionalForms = this.applicants.indexOf(amount);
    },
    setBackdrop(e) {
      this.page = e[0];
      this.heading = e[1];
    },
    reEmit(e) {
      this.$emit("deets", e);
    }
  },
  computed: {
    getForms() {
      if (this.additionalForms === 0) {
        return "/employment";
      } else {
        return "personal/additional" + this.additionalForms;
      }
    },
    noOtherForms() {
      return (
        this.$route.path === "/personal"
      );
    }
  }
};
</script>
