<template>
  <div class="spacer">
    <div class="box container has-background-white">
      <div class="columns">
        <div class="column">

          <div class="columns">
            <div class="column">
              <b-field label="What is the mortgage for?">
                <b-select placeholder="Pick one to start" expanded required v-model="propertyPage.mortgageType">
                  <option v-for="type in mortgageTypes" :value="type" :key="type">
                    {{ type }}
                  </option>
                </b-select>
              </b-field>
            </div>
            <div class="column">
              <b-field label="Do you own a property?">
                <b-select placeholder="What kind?" expanded required v-model="propertyPage.propertyType">
                  <option v-for="type in propertyTypes" :value="type" :key="type">
                    {{ type }}
                  </option>
                </b-select>
              </b-field>
            </div>
            <div class="column">
              <b-field label="Is your property in use?">
                <b-select expanded required v-model="propertyPage.occupancyType">
                  <option v-for="type in propertyOccupancy" :value="type" :key="type">
                    {{ type }}
                  </option>
                </b-select>
              </b-field>
            </div>
          </div>

          <transition name="fadeUp" mode="out-in">
            <section v-if="propertyPage.occupancyType === 'Rental'">
              <hr class="has-background-grey">
              <div class="columns">
                <div class="column">
                  <b-field label="What kind of rental is it?">
                    <b-select expanded required v-model="propertyPage.rentalProperty">
                      <option value="Ownership">
                        Ownership
                      </option>
                      <option value="Personal name">
                        Personal name
                      </option>
                      <option value="Holding company">
                        Holding company
                      </option>
                      <option value="Operating company">
                        Operating company
                      </option>
                    </b-select>
                  </b-field>
                </div>
                <div class="column">
                  <b-field label="What is your rental income per month?">
                    <b-input placeholder="Rental income" type="number" expanded v-model="propertyPage.rentalIncome">
                    </b-input>
                  </b-field>
                </div>
                <div class="column">
                  <b-field label="The rental is">
                    <div class="input is-blank">
                      <b-radio id="lease" native-value="Lease" v-model="propertyPage.rentalType">
                        Lease
                      </b-radio>
                      <b-radio id="monthly" native-value="monthly" v-model="propertyPage.rentalType">
                        Month-to-month
                      </b-radio>
                    </div>
                  </b-field>
                </div>
              </div>
              <hr class="has-background-grey">
            </section>
          </transition>

          <div class="columns">
            <div class="column">
              <b-field label="What is your property worth?">
                <b-input placeholder="Purchase price" type="number" v-model="propertyPage.purchasePrice">
                </b-input>
              </b-field>
            </div>
            <div class="column">
              <b-field label="What are your property taxes?">
                <b-input placeholder="In Canadian dollars" type="number" v-model="propertyPage.propertyTaxes">
                </b-input>
              </b-field>
            </div>
            <div class="column">
              <b-field label="Date of signing">
                <b-datepicker placeholder="Approximately" icon="calendar" v-model="propertyPage.contractSignedOn">
                </b-datepicker>
              </b-field>
            </div>
          </div>

          <div class="columns">
            <div class="column is-two-thirds">
              <b-field grouped>
                <b-field label="Unit">
                  <b-input placeholder="optional" type="number" v-model="propertyPage.propertyAddress.unit">
                  </b-input>
                </b-field>
                <b-field label="Property address" expanded>
                  <b-input icon="home" type="text" v-model="propertyPage.propertyAddress.street">
                  </b-input>
                </b-field>
              </b-field>
              <div class="columns">
                <div class="column">
                  <b-field label="City" expanded>
                    <b-input type="text" v-model="propertyPage.propertyAddress.city"></b-input>
                  </b-field>
                </div>
                <div class="column">
                  <b-field label="Province" expanded>
                    <b-input type="text" v-model="propertyPage.propertyAddress.province"></b-input>
                  </b-field>
                </div>
                <div class="column">
                  <b-field label="Postal Code" expanded>
                    <b-input type="text" v-model="propertyPage.propertyAddress.postal"></b-input>
                  </b-field>
                </div>
              </div>

            </div>
            <div class="column is-one-third">
              <div class="columns">
                <div class="column is-full">
                  <b-field label="Date of financing conditions">
                    <b-datepicker placeholder="Approximately" icon="calendar" v-model="propertyPage.conditionsDate">
                    </b-datepicker>
                  </b-field>
                </div>
              </div>
              <div class="columns">
                <div class="column is-full">
                  <b-field label="Closing date">
                    <b-datepicker placeholder="Approximately" icon="calendar" v-model="propertyPage.closingDate">
                    </b-datepicker>
                  </b-field>
                </div>
              </div>
            </div>
          </div>
          <hr>
          <transition name="fade" mode="out-in">
            <back-next back="/" next="/personal"></back-next>
          </transition>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  created() {
    this.$emit("deets", [this.page, this.heading]);
  },
  data() {
    return {
      page: "Page 1",
      heading: "Your Properties",
      mortgageTypes: [
        "Refinance",
        "Purchase",
        "Switch/Renewal",
        "Secured Line of Credit"
      ],
      propertyTypes: ["House", "Condo", "Duplex/Triplex/Fourplex"],
      propertyOccupancy: [
        "Owner occupied",
        "Owner occupied + Rental",
        "Second home",
        "Rental"
      ],
      propertyPage: {
        mortgageType: "",
        propertyType: "",
        occupancyType: "",
        // referredBy: "No",
        propertyTaxes: "",
        purchasePrice: "",
        rentalType: "",
        contractSignedOn: null,
        closingDate: null,
        conditionsDate: null,
        propertyAddress: {
          unit: "",
          city: "",
          street: "",
          province: "",
          postal: ""
        }
      }
    };
  },
  props: {
    changeComp: Function
  }
};
</script>

<style>
.box.container {
  margin-top: 100px;
}
</style>
