<template>
  <div class="spacer">
    <div class="box container has-background-white">

      <div class="columns">
        <div class="column">
          <b-field label="Applicant signature">
            <canvas id="applicant"></canvas>
          </b-field>
        </div>
        <div class="column">
          <b-field label="Guarantor signature">
            <canvas id="guarantor"></canvas>
          </b-field>
        </div>
        <div class="column">
          <b-field label="Broker signature">
            <canvas id="broker"></canvas>
          </b-field>
        </div>
      </div>

    </div>
  </div>
</template>

<script>
import SignaturePad from "signature_pad";
export default {
  created() {
    this.$emit("deets", [this.page, this.heading]);
  },
  mounted() {
    var signatures = document.querySelectorAll("canvas");
    signatures.forEach(sig => {
      new SignaturePad(sig, {
        penColor: "rgb(32, 42, 144)"
      });
    });
  },
  data() {
    return {
      page: "Page 5",
      heading: "Signatures"
    };
  },
  watch: {}
};
</script>

<style>
canvas {
  border-bottom: 1px solid black;
  width: 100%;
}
</style>
