<template>
  <div class="spacer">
    <div class="box container has-background-white">

      <div class="columns">
        <div class="column">
          <b-field label="Your employer's name">
            <b-input v-model="employmentPage.employerName"></b-input>
          </b-field>
        </div>
        <div class="column">
          <b-field label="Your current title">
            <b-input v-model="employmentPage.title"></b-input>
          </b-field>
        </div>
        <div class="column">
          <b-field label="Your employment status">
            <b-select placeholder="At this time" v-model="employmentPage.status" required expanded>
              <option value="Full-time">Full-time</option>
              <option value="Part-time">Part-time</option>
              <option value="Seasonal">Seasonal</option>
              <option value="Contract">Contract</option>
            </b-select>
          </b-field>
        </div>
      </div>

      <div class="columns">
        <div class="column is-two-thirds">
          <b-field grouped>
            <b-field label="Unit">
              <b-input placeholder="optional" type="number" v-model="employmentPage.workAddress.unit">
              </b-input>
            </b-field>
            <b-field label="Street" expanded>
              <b-input icon="home" type="text" v-model="employmentPage.workAddress.street">
              </b-input>
            </b-field>
          </b-field>
          <div class="columns">
            <div class="column">
              <b-field label="City" expanded>
                <b-input type="text" v-model="employmentPage.workAddress.city"></b-input>
              </b-field>
            </div>
            <div class="column">
              <b-field label="Province" expanded>
                <b-input type="text" v-model="employmentPage.workAddress.province"></b-input>
              </b-field>
            </div>
            <div class="column">
              <b-field label="Postal code" expanded>
                <b-input type="text" v-model="employmentPage.workAddress.postal"></b-input>
              </b-field>
            </div>
          </div>
        </div>
        <div class="column">
          <div class="columns">
            <div class="column">
              <b-field label="Industry">
                <b-input v-model="employmentPage.industry" placeholder="Most relevant"></b-input>
              </b-field>
            </div>
          </div>
          <div class="columns">
            <div class="column">
              <b-field label="How long have you worked here?">
                <b-input v-model="employmentPage.timeAtJob" placeholder="Best approximation"></b-input>
              </b-field>
            </div>
          </div>
        </div>
      </div>

      <div class="columns">
        <div class="column">
          <b-field label="Time in current industry">
            <b-input v-model="employmentPage.timeAtIndustry" placeholder="Round up to the year"></b-input>
          </b-field>
        </div>
        <div class="column">
          <b-field label="Your current income">
            <b-input v-model="employmentPage.income" placeholder="Please factor in all sources"></b-input>
          </b-field>
        </div>
        <div class="column">
          <b-field label="Are you self-employed?">
            <b-select placeholder="If yes, what category" v-model="employmentPage.selfEmployed" required expanded>
              <option value="No">No</option>
              <option value="Corporation">Corporation</option>
              <option value="Sole proprietor">Sole proprietor</option>
              <option value="Partnerhsip">Partnerhsip</option>
            </b-select>
          </b-field>
          </div>
      </div>

      <div class="columns">

        </div>

      <hr>
      <back-next back="/personal" next="/properties"></back-next>
    </div>
  </div>
</template>

<script>
export default {
  created() {
    this.$emit("deets", [this.page, this.heading]);
  },
  data() {
    return {
      page: "Page 3",
      heading: "Employment Details",
      employmentPage: {
        employerName: null,
        title: null,
        status: null,
        selfEmployed: null,
        income: null,
        timeAtIndustry: null,
        timeAtJob: null,
        workAddress: {
          street: null,
          unit: null,
          city: null,
          province: null,
          postal: null
        }
      }
    };
  }
};
</script>
