import Vue from 'vue'
import Buefy from 'buefy'
import 'buefy/lib/buefy.css'
import App from './App.vue'
import router from './router'
import store from './store'
import './registerServiceWorker'

// ####components####
import bottomNav from './components/back-next.vue'
Vue.component('back-next', bottomNav)

Vue.use(Buefy, {
  defaultIconPack: 'fas',
  defaultContainerElement: '#forms-app'
})

new Vue({
  router,
  store,
  render: h => h(App)
}).$mount('#forms-app')

Vue.config.productionTip = true