import Vue from 'vue'
import Router from 'vue-router'
import Home from './views/Home.vue'
import starterForm from './views/starter-form.vue'
import personalForm from './views/personal-form.vue'
import employmentForm from './views/employment-form.vue'
import propertiesForm from './views/properties-form.vue'
import signaturesForm from './views/signatures-form.vue'
import additionalPersonalForm from './views/additional-personal-form.vue'

Vue.use(Router)

export default new Router({
  routes: [{
      name: 'Home',
      path: '/',
      component: Home
    },
    {
      name: 'Property Form',
      path: '/start',
      component: starterForm
    },
    {
      name: 'Personal Form',
      path: '/personal',
      component: personalForm,
      children: [
        {
          name: 'Additional Personal Forms',
          path: ':amount',
          component: additionalPersonalForm
        }
      ]
    },
    {
      name: 'Employment Form',
      path: '/employment',
      component: employmentForm
    },
    {
      name: 'Properties Form',
      path: '/properties',
      component: propertiesForm
    },
    {
      name: 'Signatures Form',
      path: '/signatures',
      component: signaturesForm
    }
  ]
})